export function getErrorGuidance(
  errorCode: string,
  context: ErrorContext = {},
): ErrorGuidance {
  // Use Object.prototype.hasOwnProperty to avoid prototype pollution issues
  const guidance = Object.prototype.hasOwnProperty.call(ERROR_GUIDANCE_CATALOG, errorCode)
    ? ERROR_GUIDANCE_CATALOG[errorCode]
    : undefined;

  if (!guidance) {
    return {
      suggestions: ["Check the error message for details", "Run 'forge doctor' to diagnose common issues"],
      exampleCommands: ["forge doctor", "forge --help"],
      documentationLinks: ["https://github.com/navistone/engineering-agent-standards"],
    };
  }

  // Replace context placeholders in suggestions and commands
  const suggestions = guidance.suggestions.map(s => replaceContextPlaceholders(s, context));
  const exampleCommands = guidance.exampleCommands.map(c => replaceContextPlaceholders(c, context));

  return {
    suggestions,
    exampleCommands,
    documentationLinks: guidance.documentationLinks,
  };
}

function replaceContextPlaceholders(text: string, context: ErrorContext): string {
  return text.replace(/\{(\w+)\}/g, (match, key) => {
    const value = context[key];
    return value !== undefined ? String(value) : match;
  });
}

export function createErrorEnvelope(
  error: string,
  message: string,
  details?: Record<string, unknown>,
): ErrorEnvelope {
  // Extract context for error guidance from details
  const context: Record<string, string | number | boolean | undefined> = {};
  if (details) {
    for (const [key, value] of Object.entries(details)) {
      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
        context[key] = value;
      }
    }
  }

  // Get error recovery guidance
  const guidance = getErrorGuidance(error, context);

  // Merge guidance into details
  const enhancedDetails = {
    ...details,
    guidance: {
      suggestions: guidance.suggestions,
      exampleCommands: guidance.exampleCommands,
      documentationLinks: guidance.documentationLinks,
    },
  };

  return {
    error,
    message,
    timestamp: new Date().toISOString(),
    traceId: generateTraceId(),
    details: enhancedDetails,
  };
}

export function generateTraceId(): string {
  return uuidv4();
}

async call(
  toolName: string,
  args: Record<string, unknown>,
): Promise<Result<MCPToolResult, ErrorEnvelope>> {
  if (!this.process) {
    return Err(createErrorEnvelope('github_mcp_not_connected', 'GitHub MCP client is not connected'));
  }

  try {
    const result = await this.sendRequest('tools/call', {
      name: toolName,
      arguments: args,
    });

    return Ok(result as MCPToolResult);
  } catch (error) {
    return Err(createErrorEnvelope(
      'github_mcp_call_failed',
      `GitHub MCP tool call failed: ${error instanceof Error ? error.message : String(error)}`,
    ));
  }
}

const check = (name: string, pass: boolean, detail?: string) => {
  checks.push(`${pass ? '✓' : '✗'} ${name}${detail ? ': ' + detail : ''}`);
};

async function preflight(): Promise<Result<{ codeIndexerHealth: CodeIndexerHealthResponse }, ErrorEnvelope>> {
  const [skillResult, ciResult, mrResult] = await Promise.all([
    checkSkillApiHealth(),
    checkCodeIndexerHealth(),
    checkModelRouterHealth(),
  ]);

  // All three services are hard-fail per Q6
  if (!skillResult.ok) {
    console.warn(`[orchestrator] Skill API unavailable (non-fatal): ${skillResult.error.message}`);
    return Err(createErrorEnvelope('orchestration_preflight_failed', skillResult.error.message));
  }

  if (!ciResult.ok) {
    console.warn(`[orchestrator] Code Indexer unavailable (non-fatal): ${ciResult.error.message}`);
    return Err(createErrorEnvelope('orchestration_preflight_failed', ciResult.error.message));
  }

  // Model Router is non-fatal: when the local LLM adapter (.forge/config.yaml
  // llm.provider) handles completion directly, the router is not in the
  // request path. We still issue the health probe for observability, but a
  // failure here must not block chat turns from running against LM Studio /
  // Anthropic / OpenAI directly.
  if (!mrResult.ok) {
    console.warn(`[orchestrator] Model Router unavailable (non-fatal): ${mrResult.error.message}`);
  }

  return Ok({ codeIndexerHealth: ciResult.value });
}

export function Err<E>(error: E): Result<never, E> {
  return { ok: false, error };
}

export function Ok<T>(value: T): Result<T, never> {
  return { ok: true, value };
}

export function map<T, U, E>(
  result: Result<T, E>,
  fn: (value: T) => U,
): Result<U, E> {
  return result.ok ? Ok(fn(result.value)) : result;
}

function draftKey(userId: string, taskId: string, artifactType: ArtifactType): string {
