function draw() {
  if (!ctx) return;
  ctx.clearRect(0, 0, W, H);
  ctx.strokeStyle = 'rgba(120,120,160,0.25)';
  ctx.lineWidth = 1;
  for (const { s, t } of edgePairs) {
    const a = pos.get(s); const b = pos.get(t);
    if (!a || !b) continue;
    ctx.beginPath(); ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y); ctx.stroke();
  }
  for (const n of graph!.nodes) {
    const p = pos.get(n.id); if (!p) continue;
    const hue = LABEL_HUE[n.label] ?? 0;
    ctx.beginPath();
    ctx.arc(p.x, p.y, 5, 0, Math.PI * 2);
    ctx.fillStyle = `hsl(${hue},60%,60%)`;
    ctx.fill();
  }
}

function step() {
  if (tick >= SIM_TICKS) { draw(); return; }
  tick++;

  const ids = graph!.nodes.map(n => n.id);
  for (let i = 0; i < ids.length; i++) {
    for (let j = i + 1; j < ids.length; j++) {
      const a = pos.get(ids[i])!; const b = pos.get(ids[j])!;
      const dx = b.x - a.x; const dy = b.y - a.y;
      const d2 = dx * dx + dy * dy + 1;
      const force = REPEL / d2;
      a.vx -= force * dx; a.vy -= force * dy;
      b.vx += force * dx; b.vy += force * dy;
    }
  }
  for (const { s, t } of edgePairs) {
    const a = pos.get(s); const b = pos.get(t);
    if (!a || !b) continue;
    const dx = b.x - a.x; const dy = b.y - a.y;
    const d = Math.sqrt(dx * dx + dy * dy) + 0.01;
    const force = (d - K) * 0.05;
    a.vx += force * dx / d; a.vy += force * dy / d;
    b.vx -= force * dx / d; b.vy -= force * dy / d;
  }
  for (const p of pos.values()) {
    p.vx += (W / 2 - p.x) * 0.003; p.vy += (H / 2 - p.y) * 0.003;
    p.vx *= DAMP; p.vy *= DAMP;
    p.x = Math.max(8, Math.min(W - 8, p.x + p.vx));
    p.y = Math.max(8, Math.min(H - 8, p.y + p.vy));
  }
  draw();
  animRef.current = requestAnimationFrame(step);
}

