def search(
    self,
    vec_db_path: str,
    query: str,
    k: int = 50,
) -> list[tuple[str, float]]:
    """Return up to ``k`` ``(qualified_name, score)`` BM25 matches.

    Args:
        vec_db_path: Filesystem path to the per-repo ``.duck`` file.
        query: Free-text or identifier query — will be tokenised the same
            way as the corpus.
        k: Maximum results to return.

    Returns:
        list[tuple[str, float]]: ranked matches. Empty when the corpus is
        empty, the file is missing, the query yields no tokens, or any
        internal failure occurs (best-effort contract).
    """
    if not query or not query.strip():
        return []

    try:
        mtime = os.path.getmtime(vec_db_path)
    except OSError:
        return []

    with self._lock:
        cached = self._cache.get(vec_db_path)
        if cached is None or cached[2] != mtime:
            try:
                retriever, doc_ids = self._build(vec_db_path)
            except Exception:
                return []
            if retriever is None:
                # Empty corpus — don't cache; next index run will populate.
                return []
            self._cache[vec_db_path] = (retriever, doc_ids, mtime)
        else:
            retriever, doc_ids, _ = cached

    try:
        import bm25s

        tokens = _tokenise(query)
        if not tokens:
            return []
        query_tokens = bm25s.tokenize(" ".join(tokens), stopwords=None)
        results, scores = retriever.retrieve(
            query_tokens,
            k=min(k, len(doc_ids)),
        )
        # bm25s returns shape (n_queries, k) — we issue exactly one query.
        return [
            (doc_ids[int(idx)], float(score))
            for idx, score in zip(results[0], scores[0])
        ]
    except Exception:
        return []

def _info(msg: str) -> None:
    if not settings.QUIET:
        app_context.console.print(msg)

def load_cgrignore_patterns(repo_path: Path) -> CgrignorePatterns:
    ignore_file = repo_path / CGRIGNORE_FILENAME
    if not ignore_file.is_file():
        return EMPTY_CGRIGNORE

    exclude: set[str] = set()
    unignore: set[str] = set()
    try:
        with ignore_file.open(encoding="utf-8") as f:
            for line in f:
                # Strip whitespace AND trailing slashes so entries like
                # `.forge/` match both the directory and its descendants.
                # Without this, `.forge/`.startswith(f"{p}/") becomes
                # `.forge//` which matches nothing.
                line = line.strip().rstrip("/")
                if not line or line.startswith("#"):
                    continue
                if line.startswith("!"):
                    unignore.add(line[1:].strip().rstrip("/"))
                else:
                    exclude.add(line)
        if exclude or unignore:
            logger.info(
                logs.CGRIGNORE_LOADED.format(
                    exclude_count=len(exclude),
                    unignore_count=len(unignore),
                    path=ignore_file,
                )
            )
        return CgrignorePatterns(
            exclude=frozenset(exclude),
            unignore=frozenset(unignore),
        )
    except OSError as e:
        logger.warning(logs.CGRIGNORE_READ_FAILED.format(path=ignore_file, error=e))
        return EMPTY_CGRIGNORE

def _emit_progress(self, event: dict) -> None:
    """Fire the progress callback safely — errors never abort indexing."""
    if self._progress_cb is not None:
        try:
            self._progress_cb(event)
        except Exception:
            # Re-raise only CancelledError-style signals; swallow everything else
            # so a buggy callback cannot break the index run.
            raise

def _process_function_calls(self) -> None:
    ast_cache_items = list(self.ast_cache.items())
    for file_path, (root_node, language) in ast_cache_items:
        self.factory.call_processor.process_calls_in_file(
            file_path, root_node, language, self.queries
        )

def _group_paths_by_pattern(paths: set[str]) -> dict[str, list[str]]:
    groups: dict[str, list[str]] = {}
    for path in paths:
        key = _get_grouping_key(path)
        if key not in groups:
            groups[key] = []
        groups[key].append(path)
    for group_paths in groups.values():
        group_paths.sort()
    return groups

def _prompt_nested_selection(pattern: str, paths: list[str]) -> set[str]:
    _display_nested_table(pattern, paths)

    response = Prompt.ask(
        style(cs.INTERACTIVE_PROMPT_KEEP, cs.Color.CYAN),
        default=cs.INTERACTIVE_KEEP_NONE,
    )

    if response.lower() == cs.INTERACTIVE_KEEP_ALL:
        return set(paths)
    if response.lower() == cs.INTERACTIVE_KEEP_NONE:
        return set()

    selected: set[str] = set()
    for part in response.split(","):
        part = part.strip()
        if not part:
            continue
        if part.isdigit():
            idx = int(part) - 1
            if 0 <= idx < len(paths):
                selected.add(paths[idx])
            else:
                logger.warning(ls.EXCLUDE_INVALID_INDEX.format(index=part))
        else:
            logger.warning(ls.EXCLUDE_INVALID_INPUT.format(input=part))

    return selected

def detect_excludable_directories(repo_path: Path) -> set[str]:
    detected: set[str] = set()
    queue: deque[tuple[Path, int]] = deque([(repo_path, 0)])
    while queue:
        current, depth = queue.popleft()
        if depth > cs.INTERACTIVE_BFS_MAX_DEPTH:
            continue
        try:
            entries = list(current.iterdir())
        except PermissionError:
            continue
        for path in entries:
            if not path.is_dir():
                continue
            if path.name in cs.IGNORE_PATTERNS:
                detected.add(path.relative_to(repo_path).as_posix())
            else:
                queue.append((path, depth + 1))
    return detected

def prompt_for_unignored_directories(
    repo_path: Path,
    cli_excludes: list[str] | None = None,
) -> frozenset[str]:
    detected = detect_excludable_directories(repo_path)
    cgrignore = load_cgrignore_patterns(repo_path)
    cli_patterns = frozenset(cli_excludes) if cli_excludes else frozenset()
    pre_excluded = cli_patterns | cgrignore.exclude

    if not detected and not pre_excluded:
        return cgrignore.unignore

    all_candidates = detected | pre_excluded
    groups = _group_paths_by_pattern(all_candidates)
    sorted_roots = _display_grouped_table(groups)

    response = Prompt.ask(
        style(cs.INTERACTIVE_PROMPT_KEEP, cs.Color.CYAN),
        default=cs.INTERACTIVE_KEEP_NONE,
    )

    if response.lower() == cs.INTERACTIVE_KEEP_ALL:
        return frozenset(all_candidates) | cgrignore.unignore

    if response.lower() == cs.INTERACTIVE_KEEP_NONE:
        return cgrignore.unignore

    selected: set[str] = set()
    expand_requests: list[int] = []
    regular_selections: list[int] = []

    for part in response.split(","):
        part = part.strip().lower()
        if not part:
            continue

        if part.endswith(cs.INTERACTIVE_EXPAND_SUFFIX) and part[:-1].isdigit():
            expand_requests.append(int(part[:-1]) - 1)
        elif part.isdigit():
            regular_selections.append(int(part) - 1)
        else:
            logger.warning(ls.EXCLUDE_INVALID_INPUT.format(input=part))

    for idx in expand_requests:
        if 0 <= idx < len(sorted_roots):
            root = sorted_roots[idx]
            nested_selected = _prompt_nested_selection(root, groups[root])
            selected.update(nested_selected)
        else:
            logger.warning(ls.EXCLUDE_INVALID_INDEX.format(index=idx + 1))

    for idx in regular_selections:
        if 0 <= idx < len(sorted_roots):
            root = sorted_roots[idx]
            selected.update(groups[root])
        else:
            logger.warning(ls.EXCLUDE_INVALID_INDEX.format(index=idx + 1))

    return frozenset(selected) | cgrignore.unignore

def style(
    text: str, color: cs.Color, modifier: cs.StyleModifier = cs.StyleModifier.BOLD
) -> str:
    if modifier == cs.StyleModifier.NONE:
        return f"[{color}]{text}[/{color}]"
    return f"[{modifier} {color}]{text}[/{modifier} {color}]"

def load_parsers() -> tuple[
    dict[cs.SupportedLanguage, Parser], dict[cs.SupportedLanguage, LanguageQueries]
]:
    parsers: dict[cs.SupportedLanguage, Parser] = {}
    queries: dict[cs.SupportedLanguage, LanguageQueries] = {}
    available_languages: list[cs.SupportedLanguage] = []

    for lang_key, lang_config in deepcopy(LANGUAGE_SPECS).items():
        lang_name = cs.SupportedLanguage(lang_key)
        if _process_language(lang_name, lang_config, parsers, queries):
            available_languages.append(lang_name)

    if not available_languages:
        raise RuntimeError(ex.NO_LANGUAGES)

    logger.info(ls.INITIALIZED_PARSERS.format(languages=", ".join(available_languages)))
    return parsers, queries

def process_all_method_overrides(
    function_registry: FunctionRegistryTrieProtocol,
    class_inheritance: dict[str, list[str]],
    ingestor: IngestorProtocol,
) -> None:
    logger.info(logs.CLASS_PASS_4)

    for method_qn in function_registry.keys():
        if (
            function_registry[method_qn] == NodeType.METHOD
            and cs.SEPARATOR_DOT in method_qn
        ):
            parts = method_qn.rsplit(cs.SEPARATOR_DOT, 1)
            if len(parts) == 2:
                class_qn, method_name = parts
                check_method_overrides(
                    method_qn,
                    method_name,
                    class_qn,
                    function_registry,
                    class_inheritance,
                    ingestor,
                )

def identify_structure(self) -> None:
    directories = {self.repo_path}
    for path in self.repo_path.rglob(cs.GLOB_ALL):
        if path.is_dir() and not should_skip_path(
            path,
            self.repo_path,
            exclude_paths=self.exclude_paths,
            unignore_paths=self.unignore_paths,
        ):
            directories.add(path)

    for root in sorted(directories):
        relative_root = root.relative_to(self.repo_path)

        parent_rel_path = relative_root.parent
        parent_container_qn = self.structural_elements.get(parent_rel_path)

        is_package = False
        package_indicators: set[str] = set()

        for lang_queries in self.queries.values():
            lang_config = lang_queries[cs.QUERY_CONFIG]
            package_indicators.update(lang_config.package_indicators)

        for indicator in package_indicators:
            if (root / indicator).exists():
                is_package = True
                break

        if is_package:
            package_qn = cs.SEPARATOR_DOT.join(
                [self.project_name] + list(relative_root.parts)
            )
            self.structural_elements[relative_root] = package_qn
            logger.info(
                logs.STRUCT_IDENTIFIED_PACKAGE.format(package_qn=package_qn)
            )
            self.ingestor.ensure_node_batch(
                cs.NodeLabel.PACKAGE,
                {
                    cs.KEY_QUALIFIED_NAME: package_qn,
                    cs.KEY_NAME: root.name,
                    cs.KEY_PATH: relative_root.as_posix(),
                },
            )
            parent_identifier = self._get_parent_identifier(
                parent_rel_path, parent_container_qn
            )
            self.ingestor.ensure_relationship_batch(
                parent_identifier,
                cs.RelationshipType.CONTAINS_PACKAGE,
                (cs.NodeLabel.PACKAGE, cs.KEY_QUALIFIED_NAME, package_qn),
            )
        elif root != self.repo_path:
            self.structural_elements[relative_root] = None
            logger.info(
                logs.STRUCT_IDENTIFIED_FOLDER.format(relative_root=relative_root)
            )
            self.ingestor.ensure_node_batch(
                cs.NodeLabel.FOLDER,
                {cs.KEY_PATH: relative_root.as_posix(), cs.KEY_NAME: root.name},
            )
            parent_identifier = self._get_parent_identifier(
                parent_rel_path, parent_container_qn
            )
            self.ingestor.ensure_relationship_batch(
                parent_identifier,
                cs.RelationshipType.CONTAINS_FOLDER,
                (cs.NodeLabel.FOLDER, cs.KEY_PATH, relative_root.as_posix()),
            )
